update public.bbf_users set workout_plan=$WP$[{"day":"Day 1","focus":"Push + Core — Chest, Shoulders, Triceps & Upper Abs","exercises":[{"name":"Dumbbell Chest Press","equipment":"Dumbbells","sets":3,"reps":"12","notes":"Controlled tempo — feel the chest stretch at the bottom"},{"name":"Dumbbell Overhead Press","equipment":"Dumbbells","sets":3,"reps":"12","notes":"Core tight, no arching the lower back"},{"name":"Tricep Cable Pushdowns","equipment":"Cable","sets":3,"reps":"15","notes":"Pin elbows to ribs, extend fully at the bottom"},{"name":"Incline DB Press","equipment":"Dumbbells","sets":3,"reps":"8-12","notes":"Bench at 30-45° — controlled descent, drive through the chest at the top. Hypertrophy protocol — load to RPE 7-8."},{"name":"Planks","equipment":"Bodyweight","sets":3,"reps":"45 sec hold","notes":"Ribcage down, glutes engaged, breathe through the brace"},{"name":"Supported Knee Raises","equipment":"Captain's chair or bench","sets":3,"reps":"12","notes":"Pelvic tilt before each rep — engage lower abs, no leg swing"}]},{"day":"Day 2","focus":"Pull + Core — Back, Biceps & Obliques","exercises":[{"name":"Lat Pulldowns","equipment":"Machine","sets":3,"reps":"12","notes":"Drive elbows down, lean back slightly"},{"name":"Seated Cable Rows","equipment":"Cable","sets":3,"reps":"12","notes":"Squeeze shoulder blades together at the top"},{"name":"Dumbbell Bicep Curls","equipment":"Dumbbells","sets":3,"reps":"12","notes":"No swinging — strict, controlled form"},{"name":"Face Pulls","equipment":"Cable","sets":3,"reps":"15","notes":"Pull toward the forehead, elbows high — rear-delt focus"},{"name":"Bird-Dogs","equipment":"Bodyweight","sets":3,"reps":"12 per side","notes":"Opposite arm + leg — pause at full extension, ribs locked"},{"name":"Russian Twists","equipment":"Bodyweight or light DB","sets":3,"reps":"20","notes":"Rotate from the obliques, not the arms"}]},{"day":"Day 3","focus":"Glutes + Core — Booty Building & Pelvic Floor","exercises":[{"name":"Barbell or DB Hip Thrusts","equipment":"Barbell or Dumbbell","sets":4,"reps":"10-12","notes":"Heels close to hips, ribs down — drive glutes through the bar with a 2-sec squeeze at the top"},{"name":"Romanian Deadlifts (RDLs)","equipment":"Dumbbells or Barbell","sets":3,"reps":"12","notes":"Hip hinge — push butt back, slight knee bend, neutral spine, feel the hamstring stretch"},{"name":"Cable Pull-Throughs","equipment":"Cable","sets":3,"reps":"15","notes":"Same hinge pattern as RDLs — stand 2 ft from the stack, drive through the heels at lockout"},{"name":"Abductor Machine","equipment":"Machine","sets":3,"reps":"15-20","notes":"Slight forward lean targets glute medius — slow on the way in, 1-sec hold at full open"},{"name":"Heel Taps","equipment":"Bodyweight (supine)","sets":3,"reps":"20","notes":"Lower back pressed to the floor — alternate tapping each heel down, lower abs do the work"},{"name":"Russian Twists","equipment":"Bodyweight or light DB","sets":3,"reps":"20","notes":"Rotate from the obliques, not the arms — feet grounded if pelvic floor cues firing"}]},{"day":"Day 4","focus":"Legs (Quads & Hams) + Core — Thigh Development & Lower Abs","exercises":[{"name":"Goblet Squats","equipment":"Dumbbell or Kettlebell","sets":3,"reps":"12-15","notes":"Chest up, knees track over toes — sit between the hips, full depth without compromising posture"},{"name":"Leg Press","equipment":"Machine","sets":3,"reps":"15","notes":"Mid-foot placement — quad bias, knees track in line with toes, controlled descent"},{"name":"Leg Extensions","equipment":"Machine","sets":3,"reps":"15","notes":"Full extension, 1-sec squeeze at the top, slow eccentric — control the negative"},{"name":"Seated Leg Curls","equipment":"Machine","sets":3,"reps":"15","notes":"Drive heels down + back, 2-sec hold at full curl — feel the hamstrings, not the lower back"},{"name":"Supported Knee Raises","equipment":"Captain's chair or bench","sets":3,"reps":"12","notes":"Pelvic tilt before each rep — lower abs lift the legs, no 